import Component from 'flarum/common/Component';
const HEX_RE = /^#[0-9a-fA-F]{6}$/;
export default class ResettableColorField extends Component {
  colorInputRef = null;
  view() {
    const {
      stream,
      label,
      help,
      placeholder
    } = this.attrs;
    const value = stream() || '';
    const isValid = HEX_RE.test(value);
    const swatchColor = isValid ? value : placeholder || '#888888';
    return m("div", {
      className: "Form-group"
    }, m("label", null, label), m("div", {
      className: "ResettableColorField"
    }, m("input", {
      className: "FormControl ResettableColorField-input",
      type: "text",
      value: value,
      placeholder: placeholder || '',
      maxlength: 7,
      oninput: e => {
        const val = e.target.value;
        stream(val);
        m.redraw();
      },
      onblur: e => {
        const val = e.target.value.trim();
        // Allow empty — empty means "use forum default".
        // Only sanitise if the user typed something invalid.
        if (val !== '' && !HEX_RE.test(val)) {
          const short = val.replace(/^#?([a-f0-9])([a-f0-9])([a-f0-9])$/i, '#$1$1$2$2$3$3');
          stream(HEX_RE.test(short) ? short : '');
        } else {
          stream(val);
        }
        m.redraw();
      }
    }), m("input", {
      className: "ResettableColorField-picker",
      type: "color",
      value: isValid ? value : placeholder || '#888888',
      oncreate: vnode => {
        this.colorInputRef = vnode.dom;
      },
      oninput: e => {
        const val = e.target.value;
        stream(val);
        m.redraw();
      }
    }), m("span", {
      className: "ResettableColorField-swatch",
      style: {
        backgroundColor: swatchColor
      },
      onclick: () => this.colorInputRef?.click(),
      title: "Pick a color"
    })), help && m("div", {
      className: "helpText"
    }, help));
  }
}
flarum.reg.add('resofire-pwa', 'admin/components/ResettableColorField', ResettableColorField);